import { useState, useEffect } from 'react';
import ProductList from './components/ProductList';
import ProductModal from './components/ProductModal';
import { getProducts } from './api/api';
import './styles/main.scss';

function App() {
  const [products, setProducts] = useState([]);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState(null);

  const load = async () => { const data = await getProducts(); setProducts(data); };

  useEffect(() => { load(); }, []);

  const openModal = (product = null) => { setEditingProduct(product); setModalOpen(true); };
  const closeModal = () => { setModalOpen(false); setEditingProduct(null); };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto' }}>
      <h1 style={{ textAlign: 'center', color: '#6F4E37' }}>☕ Кофейня Bean & Brew</h1>
      <button className="btn" onClick={() => openModal()} style={{ marginBottom: '20px' }}>
        + Добавить позицию в меню
      </button>

      <ProductList 
        products={products} 
        onEdit={openModal} 
        onDelete={async (id) => { 
          await fetch(`http://localhost:3001/api/products/${id}`, { method: 'DELETE' });
          load();
        }} 
      />

      <ProductModal 
        open={modalOpen} 
        product={editingProduct} 
        onClose={closeModal} 
        onSave={load} 
      />
    </div>
  );
}

export default App;
